data.solution:
sentence: str = input()
words: list[str] = sentence.split()
words_count: int = len(words)

word_freq: dict[str, int] = {}
for word in words:
    if word not in word_freq:
        word_freq[word] = 0

    word_freq[word] += 1

repeating_words: list[tuple[str, int]] = [
    (word, word_count) for word, word_count in word_freq.items() if word_count > 1
]

print(words_count)
if repeating_words:
    for word, word_count in repeating_words:
        print(f"{word}: {word_count}")
else:
    print("Only unique words")
